import os
import logging
from logging.handlers import TimedRotatingFileHandler

# Define the log directory, make sure it exists
log_dir = '/path/to/your/logs'
os.makedirs(log_dir, exist_ok=True)

logger = logging.getLogger(__name__)
logger.setLevel(logging.INFO)

# Define the log rotation time and log file path
handler = TimedRotatingFileHandler(os.path.join(log_dir, 'my_app.log'), when='midnight', backupCount=7)

